@startuml
class Pessoa {
  + nome : String
  + endereco : String
  + cep : long
  + telefone : String
  + renda : double
  + conta : ContaComum[1..*]
}

class ContaComum {
  + numero : long
  + aberturaConta : Data
  + fechamentoConta : Date[0..1]
  + saldo : double
}

Pessoa "possui" --o "1..*" ContaComum : possui > 
@enduml
